(merge {:a 1} {:b 2} {:c 3})       ; => {:a 1 :b 2 :c 3}
(merge {:a 1} {:a 99})             ; => {:a 99}  (last wins)
(merge (hashmap/new :a 1) {:b 2})  ; hashmap with :a and :b

;; Shallow — the nested map is replaced, not merged:
(merge {:a {:x 1}} {:a {:y 2}})    ; => {:a {:y 2}}
;; deep-merge would give {:a {:x 1 :y 2}}

(match {:a [1 2]}
          ({:a [x y]} when (= (+ x y) 3) :ok)
          (_ :bad))

(deftool add-numbers
  "Add two numbers together."
  {:a {:type :number :description "First number"}
   :b {:type :number :description "Second number"}}
  (lambda (a b) (+ a b)))

(match {:x 1}
          ({:x v :y w} when #t "both")
          (_ "fallback"))

(map/from-entries '((:a 1) (:b 2)))   ; => {:a 1 :b 2}
(map/from-entries '([:a 1] [:b 2]))   ; => {:a 1 :b 2}  (vector pairs ok)
(map/from-entries (map/entries {:x 9}))   ; => {:x 9}   (roundtrip)

(match {:a {:b 42}}
          ({:a {:b v}} v)
          (_ nil))

(define (find-user id) (if (= id 1) "Alice" #f))
        (match {:method :GET :path "/users"}
          ({:method :GET :path "/users" :id id} when (find-user id)
            (find-user id))
          ({:method :GET :path "/users" :id id}
            "not-found")
          ({:method :GET :path "/users"}
            "all")
          (_ "404"))

(match {:xs '(1 2 3)}
          ({:xs [a & rest]} rest)
          (_ nil))

(match {:x 1}
          ({:keys [x y]} (list x y))
          (_ :no))

(with-span "fetch" {}
  (otel/set-attribute :http.status 200)
  (otel/set-attribute :cache.hit true))

(define (find-user id) (if (= id 1) "Alice" #f))
        (match {:method :GET :path "/users" :id 99}
          ({:method :GET :path "/users" :id id} when (find-user id)
            (find-user id))
          ({:method :GET :path "/users" :id id}
            "not-found")
          ({:method :GET :path "/users"}
            "all")
          (_ "404"))

(map/update-in {:a {:b 10}} [:a :b] #(+ % 1))       ; => {:a {:b 11}}
(map/update-in {:user {:stats {:visits 3}}}
               [:user :stats :visits]
               (fn (n) (+ n 1)))

(map/update {:a 1} :a (fn (v) (+ v 10)))         ; => {:a 11}
(map/update {:count 5} :count (fn (n) (+ n 1)))  ; => {:count 6}

;; Absent key -> f receives nil; guard against it:
(map/update {} :hits (fn (n) (+ (or n 0) 1)))    ; => {:hits 1}

(match {:type :ok :val 42}
          ({:type :ok :keys [val]} val)
          (_ nil))

(frequencies '(a b a c b a))             ; => {a 3 b 2 c 1}
(get (frequencies '(a b a c b a)) 'a)    ; => 3

;; Pair with string->list for a character tally:
(frequencies (string->list "hello"))     ; => {#\e 1 #\h 1 #\l 2 #\o 1}

(context/set :a 1)
(context/with {:b 2}
  (lambda ()
    (context/with {:c 3}
      (lambda ()
        (list (context/get :a) (context/get :b) (context/get :c))))))

(context/set :request-id "abc-123")
(log/info "handling request")
; stderr: [INFO] handling request {:request-id "abc-123"}

(context/set :a 1)
(context/set :b 2)
(context/all)  ; => {:a 1 :b 2}
